import type { ScaleLinear, ScaleLogarithmic, ScaleSymLog } from 'd3-scale';

import { DivAxisWrapper } from './DivAxisWrapper.js';
import { AxisRight } from '../AxisRight.js';
import { axisFontProps } from '../constants.js';
import { getTickLabelPropsForValueAxis } from '../utils/get-tick-label-props.js';

/**
 * @internal
 */
export interface ValueRightAxisProps {
  scale:
    | ScaleLinear<number, number>
    | ScaleLogarithmic<number, number>
    | ScaleSymLog<number, number>;
  containerWidth: number;
  containerHeight: number;
  label?: string;
  stroke?: string;
  ticks: string[];
  formattedTicks: string[];
}

const TICK_LABEL_PROPS = getTickLabelPropsForValueAxis('right');

/**
 * @internal
 */
export const ValueRightAxis = (props: ValueRightAxisProps) => {
  const {
    scale,
    containerHeight,
    containerWidth,
    label,
    stroke,
    ticks,
    formattedTicks,
  } = props;

  const tickFormat = (_: unknown, index: number) => formattedTicks[index];

  return (
    <DivAxisWrapper
      divAxisStyle={axisFontProps}
      ticks={formattedTicks}
      label={label}
    >
      <AxisRight
        role="graphics-symbol"
        aria-label="value axis right"
        scale={scale}
        containerSize={containerHeight}
        width={containerWidth}
        tickValues={ticks}
        tickLabelProps={TICK_LABEL_PROPS}
        tickFormat={tickFormat}
        label={label}
        stroke={stroke}
      />
    </DivAxisWrapper>
  );
};

ValueRightAxis['displayName'] = 'ValueRightAxis';
